import Instagram from "../../icons/instagram-w.png";
import Whatsapp from "../../icons/whatsapp-w.png";
import Facebook from "../../icons/facebook-w.png";

const Iconos = () => {
  return (
    <div className=" flex gap-[2vh]">
      <a href="https://instagram.com" 
      target="_blank" 
      rel="noopener noreferrer"
      className="w-8 h-8 rounded-full border border-white/40 hover:border[#FF5733] transition-colors duration-200 justify-center items-center flex">
        
      </a>
      <a href="https://wa.me/" target="_blank" rel="noopener noreferrer">
        <img src={Whatsapp} alt="Whatsapp" />
      </a>
      <a href="https://facebook.com" target="_blank" rel="noopener noreferrer">
        <img src={Facebook} alt="Facebook" />
      </a>
    </div>
  );
};

export default Iconos;
